// HasScan applies the HasEdge predicate on the "scan" edge.
func HasScan() predicate.ImportScanShow {
	return predicate.ImportScanShow(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ScanTable, ScanColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasScanWith applies the HasEdge predicate on the "scan" edge with a given conditions (other predicates).
func HasScanWith(preds ...predicate.ImportScan) predicate.ImportScanShow {
	return predicate.ImportScanShow(func(s *sql.Selector) {
		step := newScanStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ImportScanShow) predicate.ImportScanShow {
	return predicate.ImportScanShow(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ImportScanShow) predicate.ImportScanShow {
	return predicate.ImportScanShow(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ImportScanShow) predicate.ImportScanShow {
	return predicate.ImportScanShow(sql.NotPredicates(p))
}
